patch:
--- a/sync_counter.v
+++ b/sync_counter.v
@@ -5,7 +5,7 @@
   output reg [15:0] count
 );

-  always @(posedge clk) begin
+  always @(posedge clk or negedge reset_n) begin
     if (!reset_n)
       count <= 16'b0;
     else

before_code:
module sync_counter (
  input clk,
  input reset_n,
  output reg [15:0] count
);

  always @(posedge clk) begin
    if (!reset_n)
      count <= 16'b0;
    else
      count <= count + 1'b1;
  end
endmodule

after_code:
module sync_counter (
  input clk,
  input reset_n,
  output reg [15:0] count
);

  always @(posedge clk or negedge reset_n) begin
    if (!reset_n)
      count <= 16'b0;
    else
      count <= count + 1'b1;
  end
endmodule
